#include <iostream>
#include <fstream>
using namespace std;

int main() {

    try {
        // File Output (Write to file)
        ofstream outFile("data.txt");

        if (!outFile) {
            throw "Error opening file for writing";
        }

        outFile << "Hello from C++ File I/O!" << endl;
        outFile << "This file was created using ofstream." << endl;

        outFile.close();

        // File Input (Read from file)
        ifstream inFile("data.txt");

        if (!inFile) {
            throw "Error opening file for reading";
        }

        string line;
        cout << "Reading from file:" << endl;

        while (getline(inFile, line)) {
            cout << line << endl;
