 #include <iostream>
using namespace std;

int main() {

    int number = 10;

    // if statement
    if (number > 0) {
        cout << "The number is positive" << endl;
    }

    // if-else statement
    if (number % 2 == 0) {
        cout << "The number is even" << endl;
    } else {
        cout << "The number is odd" << endl;
    }

    // switch statement
    int day = 2;

    switch(day) {
        case 1:
            cout << "Monday" << endl;
            break;
        case 2:
            cout << "Tuesday" << endl;
            break;
        case 3:
            cout << "Wednesday" << endl;
            break;
        default:
            cout << "Other day" << endl;
    }

    return 0;
}

 #include <iostream>
