-- GROUP BY and HAVING in SQL

-- Create table
CREATE TABLE Employees (
    id INT PRIMARY KEY,
    name VARCHAR(50),
    department VARCHAR(50),
    salary DECIMAL(10,2)
);

-- Insert sample data
INSERT INTO Employees (id, name, department, salary) VALUES (1, 'Dara', 'IT', 700);
INSERT INTO Employees (id, name, department, salary) VALUES (2, 'Sokha', 'HR', 500);
INSERT INTO Employees (id, name, department, salary) VALUES (3, 'Vanna', 'IT', 800);
INSERT INTO Employees (id, name, department, salary) VALUES (4, 'Lina', 'HR', 600);

-- GROUP BY department
SELECT department, AVG(salary) AS average_salary
FROM Employees
GROUP BY department;

-- GROUP BY with HAVING condition
SELECT department, AVG(salary) AS average_salary
FROM Employees
GROUP BY department
HAVING AVG(salary) > 600;

